func min(a, b int64) int64 {
    if a < b {
        return a
    }
    return b
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
    if m == 0 || n == 0 {
        return 0
    }
    INF := int64(1) << 50
    dp0 := make([][]int64, m)
    dp1 := make([][]int64, m)
    for i := int64(0); i < m; i++ {
        dp0[i] = make([]int64, n)
        dp1[i] = make([]int64, n)
