            dp1[i][j] = INF
        }
    }

    dp1[0][0] = (0+1)*(0+1) 
    dp0[0][0] = dp1[0][0] + waitCost[0][0]

    if n > 1 {
        cost01 := (0+1) * (1+1)
        total := dp1[0][0] + cost01
        dp1[0][1] = min(dp1[0][1], total)
    }
    if m > 1 {
        cost10 := (1+1) * (0+1)
        total := dp1[0][0] + cost10
        dp1[1][0] = min(dp1[1][0], total)
    }

    for i := int64(0); i < m; i++ {
        for j := int64(0); j < n; j++ {
            currentEntryCost := (i+1)*(j+1)

            if i > 0 {
                candidate := dp0[i-1][j] + currentEntryCost
                if candidate < dp1[i][j] {
                    dp1[i][j] = candidate
                }
            }

            if j > 0 {
                candidate := dp0[i][j-1] + currentEntryCost
                if candidate < dp1[i][j] {
                    dp1[i][j] = candidate
                }
