            if dp1[i][j] < INF {
                if i != 0 || j != 0 {
                    dp0[i][j] = dp1[i][j] + waitCost[i][j]
                }
            }
        }
    }

    return min(dp1[m-1][n-1], dp0[m-1][n-1])
}
