import (
	"container/heap"
	"math"
)

type State struct {
	cost int64
	i, j int64
	p    int
}

type PriorityQueue []*State

func (pq PriorityQueue) Len() int            { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool  { return pq[i].cost < pq[j].cost }
func (pq PriorityQueue) Swap(i, j int)       { pq[i], pq[j] = pq[j], pq[i] }
func (pq *PriorityQueue) Push(x interface{}) { *pq = append(*pq, x.(*State)) }
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	x := old[n-1]
	*pq = old[:n-1]
	return x
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	if m == 0 || n == 0 {
		return 0
	}

	dist0 := make([][]int64, m)
	dist1 := make([][]int64, m)
	for i := int64(0); i < m; i++ {
		dist0[i] = make([]int64, n)
		dist1[i] = make([]int64, n)
		for j := int64(0); j < n; j++ {
			dist0[i][j] = math.MaxInt64
			dist1[i][j] = math.MaxInt64
		}
	}

	dist1[0][0] = 1
	pq := PriorityQueue{}
	heap.Push(&pq, &State{cost: 1, i: 0, j: 0, p: 1})

	for pq.Len() > 0 {
		u := heap.Pop(&pq).(*State)
		cost, i, j, p := u.cost, u.i, u.j, u.p
		if p == 0 && cost != dist0[i][j] {
			continue
		}
		if p == 1 && cost != dist1[i][j] {
			continue
		}

		if p == 0 {
			newCost := cost + waitCost[i][j]
			if newCost < dist1[i][j] {
				dist1[i][j] = newCost
				heap.Push(&pq, &State{cost: newCost, i: i, j: j, p: 1})
			}
		} else {
			if j+1 < n {
				ni, nj := i, j+1
				entryCost := (i + 1) * (j + 2)
				newCost := cost + entryCost
				if newCost < dist0[ni][nj] {
					dist0[ni][nj] = newCost
					heap.Push(&pq, &State{cost: newCost, i: ni, j: nj, p: 0})
				}
			}
			if i+1 < m {
				ni, nj := i+1, j
				entryCost := (i + 2) * (j + 1)
				newCost := cost + entryCost
				if newCost < dist0[ni][nj] {
					dist0[ni][nj] = newCost
					heap.Push(&pq, &State{cost: newCost, i: ni, j: nj, p: 0})
				}
			}
		}
	}

	ans := dist0[m-1][n-1]
	if dist1[m-1][n-1] < ans {
		ans = dist1[m-1][n-1]
	}
	return ans
}
```

### Explanation
- **Initialization**: We start by setting up distance matrices `dist0` and `dist1` to store minimum costs for states where the next step is even (waiting) or odd (moving), initialized to a large value (infinity). The starting point (0, 0) in state 1 has an initial cost of 1.
- **Priority Queue**: A min-heap is used to process states in order of increasing cost, ensuring optimal paths are explored first.
- **State Processing**:
  - **State 0 (waiting)**: The current cost is updated by adding the waiting cost of the cell, transitioning to state 1.
  - **State 1 (moving)**: The current cost is updated by adding the entry cost of adjacent cells (right or down), transitioning to state 0.
- **Termination**: The solution is the minimum cost between `dist0` and `dist1` for the destination (m-1, n-1), representing the cost of reaching the destination in state 0 or 1 respectively.

This approach efficiently explores the grid using Dijkstra's algorithm, prioritizing paths with lower costs and correctly handling the alternating movement and waiting rules to find the minimum cost path.
